const q = $('Receive Query Parameters').first().json;
const category = (q.category || 'all').toString().trim().toLowerCase();
const month = (q.month || 'all').toString().trim();
const rows = $input.all().map(i => i.json);
const filtered = rows.filter(r => {
  const rCat = (r.Category || '').toString().trim().toLowerCase();
  const rDate = (r.Date || '').toString().trim();
  const catOk = category === 'all' || rCat === category;
  const monthOk = month === 'all' || rDate.indexOf(month) === 0;
  return catOk && monthOk;
});
const total = filtered.reduce((s, r) => s + (parseFloat(r.Amount) || 0), 0);
const byCat = {};
for (const r of filtered) {
  const c = (r.Category || 'Other').toString();
  byCat[c] = (byCat[c] || 0) + (parseFloat(r.Amount) || 0);
}
const currency = filtered.length ? (filtered[0].Currency || 'EUR') : 'EUR';
return [{ json: {
  query_category: category,
  query_month: month,
  matched_transactions: filtered.length,
  total_spent: Math.round(total * 100) / 100,
  currency: currency,
  breakdown_by_category: byCat,
  transactions: filtered.map(r => ({ date: r.Date, amount: r.Amount, vendor: r.Vendor, category: r.Category }))
} }];

const item = $input.first().json;
let raw = '';
if (item && typeof item === 'object') {
  raw = (item.content && item.content.parts && item.content.parts[0] && item.content.parts[0].text) || item.text || item.output || item.response || '';
  if (!raw && Array.isArray(item.candidates)) {
    const c = item.candidates[0];
    raw = (c && c.content && c.content.parts && c.content.parts[0] && c.content.parts[0].text) || '';
  }
}
raw = (raw || '').toString();
let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch (e) {
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    try { parsed = JSON.parse(raw.slice(start, end + 1)); } catch (e2) { parsed = {}; }
  }
}
const today = new Date().toISOString().slice(0, 10);
const amt = (parsed.amount !== undefined && parsed.amount !== null && parsed.amount !== '') ? parsed.amount : 0;
return [{ json: {
  Date: parsed.date || today,
  Amount: amt,
  Currency: parsed.currency || 'EUR',
  Vendor: parsed.vendor || '',
  Category: parsed.category || 'Other',
  Note: parsed.summary || parsed.note || '',
  LoggedAt: new Date().toISOString()
} }];
